import React, { useState } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Users, 
  Phone, 
  Megaphone, 
  Shield, 
  Search, 
  Building, 
  Award,
  Menu,
  X,
  Bell,
  Settings,
  LogOut
} from 'lucide-react';
// Temporarily remove useTask to fix blinking
// import { useTask } from '../../contexts/TaskContext';

const Layout = ({ children }) => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const location = useLocation();
  // const { currentRole, setCurrentRole, stats } = useTask();
  const currentRole = null;
  const setCurrentRole = () => {};
  const stats = { total: 0, onTime: 0, approaching: 0, breached: 0 };

  // Navigation items configuration
  const navigationItems = [
    {
      name: 'Dashboard',
      path: '/',
      icon: LayoutDashboard,
      description: 'Overview & Statistics'
    },
    {
      name: 'Customer',
      path: '/customer',
      icon: Users,
      description: 'Customer Service',
      group: 'customer'
    },
    {
      name: 'Branch Staff',
      path: '/branch-staff',
      icon: Building,
      description: 'Branch Operations',
      group: 'branch-staff'
    },
    {
      name: 'Contact Center',
      path: '/contact-center',
      icon: Phone,
      description: 'Customer Support',
      group: 'contact-center'
    },
    {
      name: 'Marketing',
      path: '/marketing',
      icon: Megaphone,
      description: 'Marketing Team',
      group: 'marketing'
    },
    {
      name: 'CMD',
      path: '/cmd',
      icon: Shield,
      description: 'Management',
      group: 'cmd'
    },
    {
      name: 'Audit',
      path: '/audit',
      icon: Search,
      description: 'Investigation',
      group: 'audit'
    },
    {
      name: 'Work Unit',
      path: '/work-unit',
      icon: Building,
      description: 'Department',
      group: 'work-unit'
    },
    {
      name: 'Service Quality',
      path: '/service-quality',
      icon: Award,
      description: 'Quality Assurance',
    },
  ];

  const isActivePath = (path) => {
    return location.pathname === path;
  };

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Sidebar */}
      <div className={`${sidebarOpen ? 'w-64' : 'w-20'} bg-white shadow-lg transition-all duration-300 ease-in-out flex flex-col`}>
        {/* Header */}
        <div className="p-4 border-b border-gray-200">
          <div className="flex items-center justify-between">
            <div className={`flex items-center space-x-3 ${!sidebarOpen && 'justify-center'}`}>
              <div className="w-10 h-10 bg-primary-600 rounded-lg flex items-center justify-center">
                <Shield className="w-6 h-6 text-white" />
              </div>
              {sidebarOpen && (
                <div>
                  <h1 className="text-lg font-bold text-gray-900">CMS</h1>
                  <p className="text-xs text-gray-500">Complaint Management</p>
                </div>
              )}
            </div>
            <button
              onClick={() => setSidebarOpen(!sidebarOpen)}
              className="p-1 rounded-lg hover:bg-gray-100 transition-colors"
            >
              {sidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
            </button>
          </div>
        </div>

        {/* Current Role Display */}
        {sidebarOpen && currentRole && (
          <div className="px-4 py-3 bg-primary-50 border-b border-primary-100">
            <p className="text-xs text-primary-600 font-medium">Current Role</p>
            <p className="text-sm font-semibold text-primary-900 capitalize">
              {currentRole.replace('-', ' ')}
            </p>
          </div>
        )}

        {/* Navigation */}
        <nav className="flex-1 p-4 space-y-2">
          {navigationItems.map((item) => {
            const Icon = item.icon;
            const isActive = isActivePath(item.path);

            return (
              <NavLink
                key={item.path}
                to={item.path}
                onClick={() => item.group && handleRoleChange(item.group)}
                className={`
                  flex items-center space-x-3 px-3 py-2 rounded-lg transition-all duration-200
                  ${isActive 
                    ? 'bg-primary-100 text-primary-700 border-l-4 border-primary-600' 
                    : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
                  }
                  ${!sidebarOpen && 'justify-center'}
                `}
                title={!sidebarOpen ? `${item.name} - ${item.description}` : ''}
              >
                <Icon className="w-5 h-5 flex-shrink-0" />
                {sidebarOpen && (
                  <div className="flex-1">
                    <p className="text-sm font-medium">{item.name}</p>
                    <p className="text-xs text-gray-500">{item.description}</p>
                  </div>
                )}
              </NavLink>
            );
          })}
        </nav>

        {/* User Actions */}
        {sidebarOpen && (
          <div className="p-4 border-t border-gray-200 space-y-2">
            <button className="w-full flex items-center space-x-3 px-3 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">
              <Bell className="w-5 h-5" />
              <span className="text-sm">Notifications</span>
              {stats.total > 0 && (
                <span className="ml-auto bg-primary-100 text-primary-600 text-xs px-2 py-1 rounded-full">
                  {stats.total}
                </span>
              )}
            </button>
            <button className="w-full flex items-center space-x-3 px-3 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">
              <Settings className="w-5 h-5" />
              <span className="text-sm">Settings</span>
            </button>
            <button className="w-full flex items-center space-x-3 px-3 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">
              <LogOut className="w-5 h-5" />
              <span className="text-sm">Logout</span>
            </button>
          </div>
        )}
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Top Bar */}
        <header className="bg-white shadow-sm border-b border-gray-200 px-6 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-xl font-semibold text-gray-900">
                {navigationItems.find(item => isActivePath(item.path))?.name || 'Dashboard'}
              </h2>
              <p className="text-sm text-gray-500">
                {navigationItems.find(item => isActivePath(item.path))?.description}
              </p>
            </div>

            {/* Quick Stats */}
            <div className="flex items-center space-x-6">
              <div className="text-center">
                <p className="text-2xl font-bold text-gray-900">{stats.total}</p>
                <p className="text-xs text-gray-500">Total Tasks</p>
              </div>
              <div className="text-center">
                <p className="text-2xl font-bold text-success-600">{stats.onTime}</p>
                <p className="text-xs text-gray-500">On Time</p>
              </div>
              <div className="text-center">
                <p className="text-2xl font-bold text-warning-600">{stats.approaching}</p>
                <p className="text-xs text-gray-500">Approaching</p>
              </div>
              <div className="text-center">
                <p className="text-2xl font-bold text-danger-600">{stats.breached}</p>
                <p className="text-xs text-gray-500">Breached</p>
              </div>
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main className="flex-1 p-6 overflow-auto">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;
